// ============================================================
// SANITASI & VALIDASI INPUT (Versi Adaptasi GitHub Tanpa Underscore)
// ============================================================

const input = $input.first().json;

// Helper aman
const toStr = (val, fallback = '') => {
  if (val === undefined || val === null) return fallback;
  return String(val).trim();
};

// Ambil input dari berbagai kemungkinan format key (karena n8n suka ubah key)
let rawFile = toStr(
  input.skill_file || input.skillfile || input.skillfilepath || input.skill_file_path, ''
);
let rawTask = toStr(input.task_description || input.taskdescription || input.chatInput, 'Audit teknis');
let rawChatId = toStr(input.telegram_chat_id || input.telegramchatid || input.chat_id || input.chatid, '7218843690');

// Normalisasi untuk pencarian
const lowerFile = rawFile.toLowerCase();
let targetFile = '';

// 💥 LOOKUP TABLE: Disesuaikan dengan file GitHub Anda yang TANPA underscore
if (lowerFile.includes('security')) {
  targetFile = 'Securityskill.md';
} else if (lowerFile.includes('devops')) {
  targetFile = 'devopsskill.md';
} else if (lowerFile.includes('qa') || lowerFile.includes('test')) {
  targetFile = 'qaskill.md';
} else if (lowerFile.includes('architect') || lowerFile.includes('software')) {
  targetFile = 'softwarearchitectskill.md';
} else if (lowerFile.includes('backend')) {
  targetFile = 'backendskill.md';
} else if (lowerFile.includes('frontend')) {
  targetFile = 'Frontendskill.md';
} else {
  targetFile = 'Securityskill.md'; // Fallback aman
}

// 💥 OUTPUT JSON: Kunci (keys) dan Value 100% bebas underscore agar n8n tidak error
return {
  json: {
    valid: true,
    errors: [],
    skillfile: targetFile,
    skillfilepath: 'docs/aiskills/' + targetFile,  // ✅ Target folder baru di GitHub!
    taskdescription: rawTask,
    repoowner: toStr(input.repo_owner || input.repoowner, 'hamdallah24'),
    reponame: toStr(input.repo_name || input.reponame, 'pos-app'),
    branch: toStr(input.branch, 'Staging'),
    telegramchatid: rawChatId
  }
};

const upstream = $('Validasi OK?').first().json;

return {
  json: {
    ...upstream,
    skill_exists: true
  }
};

// Ambil data dari node sebelumnya
const input = $input.first().json;

// Ambil konten skill (dari Fetch Skill)
const skillContent = input.body || input.data || input.json || '';

// Bangun system message lengkap
const systemMessage = `
Anda adalah Specialist Agent untuk proyek POST App.

=== SKILL (SOP) ===
${skillContent}

=== INSTRUKSI ===
Gunakan skill di atas untuk menyelesaikan tugas user.

=== TOOLS YANG TERSEDIA ===
1. github_read_file - baca file dari GitHub
2. github_list_directory - lihat daftar folder

=== ATURAN ===
- Respons singkat, padat, jelas
- Gunakan bahasa Indonesia
- Jika tool gagal 2 kali, laporkan ke user
`;

// Pastikan output memiliki field yang dibutuhkan Agent
return {
  json: {
    systemMessage: systemMessage,
    task_description: input.task_description || 'Tidak ada deskripsi tugas',
    chatInput: input.task_description || 'Tidak ada deskripsi tugas'  // <-- Penting!
  }
};

// INI ADALAH FALLBACK (ERROR HANDLING)
// Jika ada error, jalankan kode ini

const input = $input.first().json;

// Ambil error message dari berbagai kemungkinan
const errorMessage = input.error || input.message || input.errorDescription || 'Unknown error';
const statusCode = input.statusCode || input.code || 500;

// Buat pesan error yang jelas
let userMessage = `❌ Terjadi kesalahan saat menjalankan sub-agent:\n\n`;
userMessage += `📌 **Error:** ${errorMessage}\n`;
userMessage += `📊 **Status Code:** ${statusCode}\n\n`;

// Tambahkan saran perbaikan berdasarkan error
if (statusCode === 404) {
  userMessage += `💡 **Saran:** File skill '${input.skillfile || input.skill_file || 'unknown'}' tidak ditemukan.\n`;
  userMessage += `Pastikan nama file benar dan sudah di-upload ke docs/ai_skills/\n`;
  userMessage += `Di repository: ${input.repo_owner || '?'}/${input.repo_name || '?'}`;
} else if (statusCode === 401) {
  userMessage += `💡 **Saran:** Token GitHub tidak valid atau expired.\n`;
  userMessage += `Periksa credential GitHub di n8n.`;
} else if (statusCode === 403) {
  userMessage += `💡 **Saran:** Rate limit GitHub tercapai. Tunggu beberapa menit.`;
} else {
  userMessage += `💡 **Saran:** Periksa input dan coba lagi.\n`;
  userMessage += `Input: ${JSON.stringify(input, null, 2)}`;
}

return {
  json: {
    error: true,
    message: userMessage,
    raw: input
  }
};
